<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shell</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run-as</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> com.notedx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 切换到 NotedX 的 UID</span></span>
